function makeModules(
  mod1: Question[],
  mod2Easy: Question[],
  mod2Hard: Question[],
  section: "reading" | "math",
  time1: number,
  time2: number,
): Module[] {
  return [
    { id: 1, section, difficulty: "medium", questions: mod1, timeLimitMinutes: time1 },
    { id: 2, section, difficulty: "easy", questions: mod2Easy, timeLimitMinutes: time2 },
    { id: 3, section, difficulty: "hard", questions: mod2Hard, timeLimitMinutes: time2 },
  ];
}

