function englishForMock(mockIdx: number) {
  const m = mockEnglish[mockIdx];
  return {
    m1: m.m1.map((q, i) => ({ ...q, type: 'mcq' as const, section: 'reading' as const, questionNumber: i + 1, module: 1, difficulty: 'medium' as const }) as Question),
    m2e: m.m2e.map((q, i) => ({ ...q, type: 'mcq' as const, section: 'reading' as const, questionNumber: i + 1, module: 2, difficulty: 'easy' as const }) as Question),
    m2h: m.m2h.map((q, i) => ({ ...q, type: 'mcq' as const, section: 'reading' as const, questionNumber: i + 1, module: 2, difficulty: 'hard' as const }) as Question),
  };
}

function mathForMock(mockIdx: number) {
  return {
    m1: mathQuestions.slice(mockIdx * 22, mockIdx * 22 + 22).map((q, i) => ({ ...q, questionNumber: i + 1 })),
    m2e: mathQuestions.slice(660 + mockIdx * 22, 660 + mockIdx * 22 + 22).map((q, i) => ({ ...q, module: 2 as const, difficulty: 'easy' as const, questionNumber: i + 1 })),
    m2h: mathQuestions.slice(1320 + mockIdx * 26, 1320 + mockIdx * 26 + 26).map((q, i) => ({ ...q, module: 2 as const, difficulty: 'hard' as const, questionNumber: i + 1 })),
  };
}

function make2Modules(
  mod1: Question[],
  mod2: Question[],
  section: "reading" | "math",
  time1: number,
  time2: number,
): Module[] {
  return [
    { id: 1, section, difficulty: "medium", questions: mod1, timeLimitMinutes: time1 },
    { id: 2, section, difficulty: "medium", questions: mod2, timeLimitMinutes: time2 },
  ];
}

export const mockTests: MockTest[] = Array.from({ length: 15 }, (_, i) => {
  const en = englishForMock(i);
  if (i === 0) {
    return {
      id: "mock-1",
      name: "Practice Test 1",
      readingModules: make2Modules(en.m1, en.m2e, 'reading', 32, 32),
      mathModules: makeModules(mock1MathModule1, mock1MathModule2, mock1MathModule2, 'math', 35, 35),
    };
  }
  if (i === 1) {
    return {
      id: "mock-2",
      name: "Practice Test 2",
      readingModules: makeModules(
        mock2EnglishModule1,
        mock2EnglishModule2.slice(0, 27).map((q, i) => ({ ...q, questionNumber: i + 1, module: 2 })),
        mock2EnglishModule2.slice(23).map((q, i) => ({ ...q, questionNumber: i + 1, module: 2 })),
        'reading', 32, 32,
      ),
      mathModules: makeModules(mock2MathModule1, mock2MathModule2, mock2MathModule2, 'math', 35, 35),
    };
  }
  const math = mathForMock(i);
  return {
    id: `mock-${i + 1}`,
    name: `Practice Test ${i + 1}`,
    readingModules: make2Modules(en.m1, en.m2e, 'reading', 32, 32),
    mathModules: makeModules(math.m1, math.m2e, math.m2h, 'math', 35, 35),
  };
});
